async function load3DModel(url) {
  if (url.endsWith(".stl")) {
    const loader = new STLLoader2();
    const geometry = await loader.loadAsync(url);
    const material = new THREE41.MeshStandardMaterial({
      color: 8947848,
      metalness: 0.5,
      roughness: 0.5
    });
    return new THREE41.Mesh(geometry, material);
  }
  if (url.endsWith(".obj")) {
    const loader = new OBJLoader2();
    return await loader.loadAsync(url);
  }
  if (url.endsWith(".wrl")) {
    return await loadVrml(url);
  }
  if (url.endsWith(".gltf") || url.endsWith(".glb")) {
    const loader = new GLTFLoader2();
    const gltf = await loader.loadAsync(url);
    return gltf.scene;
  }
  console.error("Unsupported file format or failed to load 3D model.");
  return null;
}

